@Configuration
class ElasticsearchConfig {

    @Value("${elasticsearch.host}")
    private String host;

    @Value("${elasticsearch.port}")
    private int port;

    @Bean
    public RestHighLevelClient elasticsearchClient() {
        return new RestHighLevelClient(
            org.elasticsearch.client.RestClient.builder(
                new org.apache.http.HttpHost(host, port, "http")
            )
        );
    }
}

@Service
class ElasticsearchService {

    @Autowired
    private RestHighLevelClient client;

    private static final String PRODUCT_INDEX = "products";
    private static final String QUERY_INDEX = "search_queries";

    public ElasticsearchService() {
    }

    public String indexProduct(Product product) throws IOException {
        if (!indexExists(PRODUCT_INDEX)) {
            createProductIndex();
        }

        IndexRequest request = new IndexRequest(PRODUCT_INDEX);
        request.id(product.getId());
        request.source(product.toJson(), XContentType.JSON);
        return client.index(request, RequestOptions.DEFAULT).getId();
    }

    public SearchResponse searchProducts(String query, int from, int size, String[] categories, String[] brands) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        
        if (query != null && !query.trim().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description", "tags")
                .type("best_fields")
                .fuzziness("AUTO"));
        }
        
        if (categories != null && categories.length > 0) {
            boolQuery.filter(QueryBuilders.termsQuery("categories", categories));
        }
        
        if (brands != null && brands.length > 0) {
            boolQuery.filter(QueryBuilders.termsQuery("brands", brands));
        }
        
        searchSourceBuilder.query(boolQuery);
        searchSourceBuilder.from(from);
        searchSourceBuilder.size(size);
        
        searchSourceBuilder.sort(SortBuilders.scoreSort());
        searchSourceBuilder.sort("name.keyword", SortOrder.ASC);
        
        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field("name");
        highlightBuilder.field("description");
        highlightBuilder.field("tags");
        highlightBuilder.preTags("<mark>");
        highlightBuilder.postTags("</mark>");
        searchSourceBuilder.highlighter(highlightBuilder);
        
        searchRequest.source(searchSourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    public Map<String, Object> getFacets(String query, String[] categories, String[] brands) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        
        if (query != null && !query.trim().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description", "tags")
                .type("best_fields")
                .fuzziness("AUTO"));
        }
        
        if (categories != null && categories.length > 0) {
            boolQuery.filter(QueryBuilders.termsQuery("categories", categories));
        }
        
        if (brands != null && brands.length > 0) {
            boolQuery.filter(QueryBuilders.termsQuery("brands", brands));
        }
        
        searchSourceBuilder.query(boolQuery);
        searchSourceBuilder.size(0);
        
        searchSourceBuilder.aggregation(
            QueryBuilders.termsAggregation("categories_agg")
                .field("categories")
                .size(100)
        );
        
        searchSourceBuilder.aggregation(
            QueryBuilders.termsAggregation("brands_agg")
                .field("brands")
                .size(100)
        );
        
        searchRequest.source(searchSourceBuilder);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);
        
        Map<String, Object> facets = new HashMap<>();
        facets.put("categories", response.getAggregations().get("categories_agg"));
        facets.put("brands", response.getAggregations().get("brands_agg"));
        
        return facets;
    }

    public void saveQuery(SearchQuery searchQuery) throws IOException {
        if (!indexExists(QUERY_INDEX)) {
            createQueryIndex();
        }

        IndexRequest request = new IndexRequest(QUERY_INDEX);
        request.source(searchQuery.toJson(), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    private boolean indexExists(String indexName) throws IOException {
        GetIndexRequest request = new GetIndexRequest(indexName);
        return client.indices().exists(request, RequestOptions.DEFAULT);
    }

    private void createProductIndex() throws IOException {
        CreateIndexRequest request = new CreateIndexRequest(PRODUCT_INDEX);
        request.settings(Settings.builder()
            .put("index.number_of_shards", 1)
            .put("index.number_of_replicas", 1)
        );
        
        request.mapping(
            "{\n" +
            "  \"properties\": {\n" +
            "    \"id\": {\"type\": \"keyword\"},\n" +
            "    \"name\": {\n" +
            "      \"type\": \"text\",\n" +
            "      \"analyzer\": \"standard\",\n" +
            "      \"fields\": {\n" +
            "        \"keyword\": {\"type\": \"keyword\"}\n" +
            "      }\n" +
            "    },\n" +
            "    \"description\": {\n" +
            "      \"type\": \"text\",\n" +
            "      \"analyzer\": \"standard\"\n" +
            "    },\n" +
            "    \"price\": {\"type\": \"float\"},\n" +
            "    \"categories\": {\"type\": \"keyword\"},\n" +
            "    \"brands\": {\"type\": \"keyword\"},\n" +
            "    \"tags\": {\"type\": \"text\"},\n" +
            "    \"inStock\": {\"type\": \"boolean\"}\n" +
            "  }\n" +
            "}", XContentType.JSON);
        
        client.indices().create(request, RequestOptions.DEFAULT);
    }

    private void createQueryIndex() throws IOException {
        CreateIndexRequest request = new CreateIndexRequest(QUERY_INDEX);
        request.settings(Settings.builder()
            .put("index.number_of_shards", 1)
            .put("index.number_of_replicas", 1)
        );
        
        request.mapping(
            "{\n" +
            "  \"properties\": {\n" +
            "    \"query\": {\"type\": \"text\"},\n" +
            "    \"timestamp\": {\"type\": \"date\"},\n" +
            "    \"userId\": {\"type\": \"keyword\"}\n" +
            "  }\n" +
            "}", XContentType.JSON);
        
        client.indices().create(request, RequestOptions.DEFAULT);
    }
}

